def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        steps = 10
        penalty = 0
        bonus = 0
        for step in range(steps):
            exp_component = np.exp(-ratio * (step + 1))
            tanh_component = np.tanh(ratio * 15 * (step + 1))
            log_component = np.log1p(ratio * 150) / (step + 1.5)
            sin_component = np.sin(ratio * np.pi * (step + 0.75)) ** 3
            cos_component = np.cos(ratio * np.pi * (step + 0.25)) ** 2
            composite = (exp_component + tanh_component) * decay + log_component * decay + sin_component * decay * 0.5 - cos_component * decay * 0.3
            if ratio < 0.2:
                composite += (7 - step) * 0.4 * decay
            elif 0.4 < ratio < 0.6:
                composite -= (step ** 2) * 0.2 * decay
            elif 0.8 < ratio < 1:
                composite += step * 0.15 * decay
            else:
                composite += 0.25 * step * decay
            score += composite
            decay *= 0.68
            if score > 25:
                penalty += step * 0.7
                break
        if ratio < 0.4:
            for k in range(4):
                score += ((0.6 / (k + 1)) * (1 - ratio)) ** 3
        elif 0.5 < ratio < 0.75:
            for k in range(3):
                if capacity < item * (1 + 0.15 * k):
                    score += 4 * (k + 1)
                    penalty += k * 1.5
        if capacity < item * 0.9:
            penalty += 30
        if capacity > item * 2.5:
            bonus += score * 0.3
            score /= 2.5
        if ratio > 1.2:
            penalty += 40
        if penalty > 0:
            score += penalty
        score -= bonus
        if 0.95 <= ratio <= 1.05:
            score *= 0.5
            score -= 2
        if score < 0:
            score = 0
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 250
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 1.8
            else:
                normalized = (priorities[i] - p_min) / (p_max - p_min)
                priorities[i] = (normalized ** 1.5) * 25
    return priorities
